import { overlayHub, type OverlayHub } from '@arvo/core';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type ArvoToastType = 'negative' | 'warning' | 'info' | 'positive' | 'block' | 'neutral';
export type ArvoToastPosition = 'top-right' | 'top-left' | 'bottom-right' | 'bottom-left';
export type ArvoToastCloseReason = 'click' | 'escape' | 'fade' | 'programmatic';

export interface ArvoToastOptions {
  type?: ArvoToastType;
  title?: string | null;
  message: string;
  fadeAway?: boolean;
  timeout?: number;
  pauseOnHover?: boolean;
  icon?: string | null;
  link?: HTMLElement | null;
  onClose?: () => void;
}

export interface ArvoToastManagerOptions {
  position?: ArvoToastPosition;
  timeout?: number;
  pauseOnHover?: boolean;
  /** Custom overlay hub instance. Falls back to the module-level singleton. */
  hub?: OverlayHub;
}

// ---------------------------------------------------------------------------
// Internal per-toast state
// ---------------------------------------------------------------------------

interface ToastState {
  id: string;
  element: HTMLDivElement;
  timer: ReturnType<typeof setTimeout> | null;
  removed: boolean;
  options: Required<Omit<ArvoToastOptions, 'link' | 'onClose'>> & {
    link: HTMLElement | null;
    onClose: (() => void) | null;
  };
}

const NO_AUTO_DISMISS: ReadonlySet<ArvoToastType> = new Set(['negative', 'block']);
const ALERT_ROLES: ReadonlySet<ArvoToastType> = new Set(['negative', 'block']);

let idCounter = 0;

// ---------------------------------------------------------------------------
// ArvoToast — imperative toast manager
// ---------------------------------------------------------------------------

export class ArvoToast {
  private _container: HTMLDivElement | null = null;
  private _toasts = new Map<string, ToastState>();
  private _defaults: Required<Omit<ArvoToastManagerOptions, 'hub'>>;
  private _hub: OverlayHub;
  private _overlayId: string;
  private _destroyed = false;

  static initialize(
    container?: HTMLElement | string | null,
    options?: ArvoToastManagerOptions,
  ): ArvoToast {
    return new ArvoToast(container, options);
  }

  constructor(
    container?: HTMLElement | string | null,
    options?: ArvoToastManagerOptions,
  ) {
    this._defaults = {
      position: options?.position ?? 'top-right',
      timeout: options?.timeout ?? 5000,
      pauseOnHover: options?.pauseOnHover ?? true,
    };

    this._hub = options?.hub ?? overlayHub;
    this._overlayId = `arvo-toast-container-${++idCounter}`;

    // Build container
    const el = document.createElement('div');
    el.className = `arvo-toast-container arvo-toast-container--${this._defaults.position}`;
    el.setAttribute('role', 'region');
    el.setAttribute('aria-label', 'Notifications');
    this._container = el;

    // Resolve parent
    let parent: HTMLElement = document.body;
    if (typeof container === 'string') {
      parent = document.querySelector(container) as HTMLElement ?? document.body;
    } else if (container instanceof HTMLElement) {
      parent = container;
    }
    parent.appendChild(el);

    this._hub.open({
      id: this._overlayId,
      type: 'toast',
      element: el,
      priority: 0,
      config: { autoCloseOnOutsideClick: false },
    });
  }

  // ── show ─────────────────────────────────────────────────────────────

  show(options: ArvoToastOptions): string {
    if (this._destroyed || !this._container) return '';

    const type: ArvoToastType = options.type ?? 'info';
    const shouldFade = NO_AUTO_DISMISS.has(type) ? false : (options.fadeAway ?? true);
    const timeout = options.timeout ?? this._defaults.timeout;
    const pauseOnHover = options.pauseOnHover ?? this._defaults.pauseOnHover;
    const role = ALERT_ROLES.has(type) ? 'alert' : 'status';

    const id = `arvo-toast-${++idCounter}`;

    const state: ToastState = {
      id,
      element: null!,
      timer: null,
      removed: false,
      options: {
        type,
        title: options.title ?? null,
        message: options.message,
        fadeAway: shouldFade,
        timeout,
        pauseOnHover,
        icon: options.icon ?? null,
        link: options.link ?? null,
        onClose: options.onClose ?? null,
      },
    };

    // Build DOM
    const toast = document.createElement('div');
    const classes = ['arvo-toast', `arvo-toast--${type}`];
    toast.className = classes.join(' ');
    toast.setAttribute('role', role);
    toast.setAttribute('aria-atomic', 'true');

    // Icon
    const icoClasses = ['arvo-toast__ico', 'o9con'];
    if (state.options.icon) icoClasses.push(`o9con-${state.options.icon}`);
    const ico = document.createElement('span');
    ico.className = icoClasses.join(' ');
    ico.setAttribute('aria-hidden', 'true');
    toast.appendChild(ico);

    // Content
    const content = document.createElement('div');
    content.className = 'arvo-toast__content';

    const textWrap = document.createElement('div');
    if (state.options.title) {
      const titleEl = document.createElement('p');
      titleEl.className = 'arvo-toast__title';
      titleEl.textContent = state.options.title;
      textWrap.appendChild(titleEl);
    }
    const msgEl = document.createElement('p');
    msgEl.className = 'arvo-toast__msg';
    msgEl.textContent = state.options.message;
    textWrap.appendChild(msgEl);
    content.appendChild(textWrap);

    if (state.options.link) {
      const linkWrap = document.createElement('div');
      linkWrap.className = 'arvo-toast__link';
      linkWrap.appendChild(state.options.link);
      content.appendChild(linkWrap);
    }
    toast.appendChild(content);

    // Close button
    const closeBtn = document.createElement('button');
    closeBtn.className = 'arvo-toast__close';
    closeBtn.setAttribute('aria-label', 'Close notification');
    closeBtn.setAttribute('type', 'button');
    const closeIco = document.createElement('span');
    closeIco.className = 'o9con o9con-close';
    closeBtn.appendChild(closeIco);
    toast.appendChild(closeBtn);

    state.element = toast;
    this._toasts.set(id, state);

    // Insert at top
    this._container.insertBefore(toast, this._container.firstChild);

    // Event listeners
    closeBtn.addEventListener('click', () => this._remove(id, 'click'));

    toast.addEventListener('keydown', (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.stopPropagation();
        this._remove(id, 'escape');
      }
    });

    if (shouldFade) {
      this._startFadeTimer(state, timeout);

      if (pauseOnHover) {
        toast.addEventListener('mouseenter', () => {
          if (state.timer) { clearTimeout(state.timer); state.timer = null; }
          toast.classList.add('is-paused');
          toast.classList.remove('is-fading');
        });

        toast.addEventListener('mouseleave', () => {
          toast.classList.remove('is-paused');
          this._startFadeTimer(state, timeout);
        });
      }
    }

    return id;
  }

  // ── close ────────────────────────────────────────────────────────────

  close(id: string): void {
    this._remove(id, 'programmatic');
  }

  // ── closeAll ─────────────────────────────────────────────────────────

  closeAll(): void {
    const ids = [...this._toasts.keys()];
    for (const id of ids) {
      this._remove(id, 'programmatic');
    }
  }

  // ── destroy ──────────────────────────────────────────────────────────

  destroy(): void {
    if (this._destroyed) return;
    this._destroyed = true;
    this.closeAll();
    this._hub.close(this._overlayId);
    this._container?.remove();
    this._container = null;
  }

  // ── internal helpers ─────────────────────────────────────────────────

  private _startFadeTimer(state: ToastState, timeout: number): void {
    state.timer = setTimeout(() => {
      const el = state.element;
      el.classList.add('is-fading');
      el.classList.remove('is-paused');
      const onEnd = () => {
        el.removeEventListener('transitionend', onEnd);
        this._remove(state.id, 'fade');
      };
      el.addEventListener('transitionend', onEnd);
    }, timeout);
  }

  private _remove(id: string, reason: ArvoToastCloseReason): void {
    const state = this._toasts.get(id);
    if (!state || state.removed) return;
    state.removed = true;

    if (state.timer) { clearTimeout(state.timer); state.timer = null; }

    state.options.onClose?.();
    state.element.remove();
    this._toasts.delete(id);

    this._container?.dispatchEvent(new CustomEvent('toast:close', {
      bubbles: true,
      cancelable: false,
      detail: { id, reason },
    }));
  }
}
